snippets.css:
body {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding: 32px 16px;
  font-family: system-ui, sans-serif;
}
.card {
  background: var(--sn-muted);
  border: 1px solid var(--sn-border);
  border-radius: 16px;
  padding: 32px 24px;
  max-width: 340px;
  width: 100%;
  text-align: center;
}
.avatar {
  font-size: 2.5rem;
  margin-bottom: 12px;
}
.name {
  margin: 0 0 8px;
  font-size: 1.2rem;
  font-weight: 700;
}
.bio {
  margin: 0 0 16px;
  font-size: 0.85rem;
  color: var(--sn-muted-fg);
  line-height: 1.5;
}
.tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  justify-content: center;
  margin-bottom: 20px;
}
.tag {
  background: var(--sn-bg);
  border: 1px solid var(--sn-border);
  border-radius: 99px;
  font-size: 0.72rem;
  padding: 3px 10px;
  font-family: monospace;
}
.cta {
  background: var(--sn-primary);
  color: var(--sn-primary-fg);
  border: none;
  border-radius: var(--sn-radius);
  padding: 10px 28px;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.15s;
}
.cta:hover { opacity: 0.85; }

snippets.js:
function render(){
  var u=window.__sn_user;
  if(u&&u.username){
    document.getElementById('avatar').textContent='👋';
    document.getElementById('greeting').textContent='Hello, '+u.username+'!';
    document.getElementById('sub').textContent='Role: '+u.role+' · You are signed in.';
  } else {
    document.getElementById('avatar').textContent='👤';
    document.getElementById('greeting').textContent='Hello, Guest!';
    document.getElementById('sub').textContent='Log in or register to get a personalised greeting.';
  }
}
render();
// Re-render if user changes without page reload
document.addEventListener('sn:userchange', render);
